"""Blockchain Wallet -- HD wallet, BIP32/39/44 key derivation, address generation."""
from dataclasses import dataclass
from pathlib import Path
import json, hashlib, hmac, base64

@dataclass
class WalletAccount:
    account_id: str = ""
    path: str = ""
    address: str = ""
    public_key: str = ""
    private_key_enc: str = ""
    balance: float = 0.0
    nonce: int = 0

class BlockchainWallet:
    def __init__(self, root: str = "."):
        self.root = Path(root)
        self._accounts: dict[str, WalletAccount] = {}
        self._master_seed: str = ""
        self._persist_path = self.root / "wallet.json"
        self._load()

    def _load(self) -> None:
        if self._persist_path.exists():
            data = json.loads(self._persist_path.read_text())
            self._accounts = {k: WalletAccount(**v) for k, v in data.get("accounts", {}).items()}
            self._master_seed = data.get("master_seed", "")

    def _save(self) -> None:
        self._persist_path.write_text(json.dumps({
            "accounts": {k: v.__dict__ for k, v in self._accounts.items()},
            "master_seed": self._master_seed
        }, indent=2))

